use light_program_profiler::profile;
use pinocchio::{AccountView, Address, ProgramResult};

pub mod benchmarks;
pub mod instructions;

pub use instructions::discriminator::PlonkBenchInstruction;

// Generated by build.rs
include!(concat!(env!("OUT_DIR"), "/verifying_key.rs"));
include!(concat!(env!("OUT_DIR"), "/test_proof.rs"));
include!(concat!(env!("OUT_DIR"), "/test_public_inputs.rs"));

#[profile]
pub fn baseline_empty_function() {}

#[cfg(not(feature = "no-entrypoint"))]
pinocchio::program_entrypoint!(process_instruction);

#[cfg(not(feature = "no-entrypoint"))]
pinocchio::default_panic_handler!();

pub fn process_instruction(
    _program_id: &Address,
    _accounts: &[AccountView],
    instruction_data: &[u8],
) -> ProgramResult {
    let instruction = PlonkBenchInstruction::try_from(instruction_data)?;
    let discriminator = u16::from_le_bytes([instruction_data[0], instruction_data[1]]);

    if discriminator < 30 {
        instructions::process_instruction_0_29::process_instruction_0_29(instruction)
    } else {
        instructions::process_instruction_30_59::process_instruction_30_59(instruction)
    }
}
